// @ts-nocheck
//
// Skyline Runner — a tiny endless rooftop runner.
// A little figure sprints across the tops of buildings; tap / space to jump
// the gaps. It speeds up the longer you survive, and the sky cycles through
// sunrise, day, sunset and night as you play.
//
// Rendering is deliberately lightweight (no postprocessing, capped pixel
// ratio) so it stays smooth on old machines.

import * as THREE from 'three';

// ----------------------------------------------------------------- tuning
const CHAR_X = -3.5; // fixed horizontal position of the runner
const GRAVITY = 42;
const JUMP_V = 14;
const START_SPEED = 7;
const MAX_SPEED = 18;
const SPEED_RAMP = 0.16; // units/sec added per second of play
const DEATH_Y = 0.6; // fall below this (into a gap) and it's game over
const CULL_X = -11; // recycle buildings once they pass this
const SPAWN_AHEAD = 13; // keep buildings generated this far ahead
const BASE_TOP = 3.4; // nominal rooftop height
const DEPTH = 2.4; // building depth (z)
const CYCLE_SECONDS = 70; // length of one full day/night cycle

const isLowEndDevice =
  (typeof navigator !== 'undefined' &&
    ((navigator.hardwareConcurrency || 8) <= 4 ||
      (navigator.deviceMemory || 8) <= 4)) ||
  (typeof window !== 'undefined' && window.innerWidth <= 800);

// Sky keyframes, keyed by sun elevation e (sin of the sun angle, -1..1).
// Interpolating by elevation gives sunrise and sunset for free (both pass
// through the warm horizon colours as e crosses zero).
const SKY_STOPS = [
  { e: -1.0, sky: '#05030f', building: '#080616', accent: '#5fd6ff', amb: 0.25, sun: 0.05 },
  { e: -0.25, sky: '#1d1140', building: '#0d0a20', accent: '#9b6cff', amb: 0.35, sun: 0.1 },
  { e: -0.05, sky: '#6b2a5e', building: '#150f2c', accent: '#ff7eb0', amb: 0.5, sun: 0.35 },
  { e: 0.05, sky: '#ef6d4a', building: '#241432', accent: '#ffd36e', amb: 0.72, sun: 0.85 },
  { e: 0.25, sky: '#ff9e5a', building: '#2a1d3a', accent: '#fff0c0', amb: 0.88, sun: 1.05 },
  { e: 0.6, sky: '#4f93d6', building: '#243049', accent: '#bfe6ff', amb: 1.0, sun: 1.15 },
  { e: 1.0, sky: '#7ec3ef', building: '#2b3a55', accent: '#e8f7ff', amb: 1.05, sun: 1.2 },
];

const clamp01 = (x: number) => Math.max(0, Math.min(1, x));
const lerp = (a: number, b: number, t: number) => a + (b - a) * t;

// Resolve a colour/number field across the keyframes at elevation e.
const tmpA = new THREE.Color();
const tmpB = new THREE.Color();
function rampColor(out: THREE.Color, field: string, e: number) {
  for (let i = 0; i < SKY_STOPS.length - 1; i++) {
    const s0 = SKY_STOPS[i];
    const s1 = SKY_STOPS[i + 1];
    if (e <= s1.e || i === SKY_STOPS.length - 2) {
      const t = clamp01((e - s0.e) / (s1.e - s0.e));
      tmpA.set(s0[field]);
      tmpB.set(s1[field]);
      return out.copy(tmpA).lerp(tmpB, t);
    }
  }
  return out.set(SKY_STOPS[0][field]);
}
function rampNum(field: string, e: number) {
  for (let i = 0; i < SKY_STOPS.length - 1; i++) {
    const s0 = SKY_STOPS[i];
    const s1 = SKY_STOPS[i + 1];
    if (e <= s1.e || i === SKY_STOPS.length - 2) {
      const t = clamp01((e - s0.e) / (s1.e - s0.e));
      return lerp(s0[field], s1[field], t);
    }
  }
  return SKY_STOPS[0][field];
}

function rand(min: number, max: number) {
  return min + Math.random() * (max - min);
}

// ----------------------------------------------------------------- entry point
export default function StartThreeJS(cityRef: any, hooks: any = {}) {
  const reportScore = hooks.onScore || (() => {});
  const reportState = hooks.onState || (() => {});
  const reportHigh = hooks.onHigh || (() => {});

  const container = cityRef.current;
  if (!container) return () => {};

  // --- renderer
  const renderer = new THREE.WebGLRenderer({
    antialias: !isLowEndDevice,
    powerPreference: 'high-performance',
  });
  renderer.setPixelRatio(Math.min(window.devicePixelRatio, isLowEndDevice ? 1 : 1.5));
  renderer.setSize(window.innerWidth, window.innerHeight);
  container.appendChild(renderer.domElement);

  // --- scene + camera
  const scene = new THREE.Scene();
  const fog = new THREE.Fog('#1d1140', 18, 46);
  scene.fog = fog;

  const camera = new THREE.PerspectiveCamera(28, window.innerWidth / window.innerHeight, 0.1, 200);
  camera.position.set(0, 4.2, 17);
  camera.lookAt(0, 3.3, 0);

  // --- lights
  const ambient = new THREE.AmbientLight('#ffffff', 0.7);
  scene.add(ambient);
  const sunLight = new THREE.DirectionalLight('#ffffff', 1);
  scene.add(sunLight);

  // --- celestial disc (sun / moon)
  const sunMat = new THREE.MeshBasicMaterial({ color: '#ffd36e', fog: false });
  const sun = new THREE.Mesh(new THREE.CircleGeometry(1.7, 32), sunMat);
  sun.position.z = -18;
  scene.add(sun);
  const glowMat = new THREE.SpriteMaterial({
    map: makeGlowTexture(),
    color: '#ffd36e',
    transparent: true,
    opacity: 0.8,
    depthWrite: false,
    fog: false,
  });
  const sunGlow = new THREE.Sprite(glowMat);
  sunGlow.scale.set(11, 11, 1);
  sun.add(sunGlow);

  // --- stars (fade in at night)
  const starGeo = new THREE.BufferGeometry();
  const starCount = isLowEndDevice ? 120 : 260;
  const starPos = new Float32Array(starCount * 3);
  for (let i = 0; i < starCount; i++) {
    starPos[i * 3] = rand(-30, 30);
    starPos[i * 3 + 1] = rand(2, 22);
    starPos[i * 3 + 2] = rand(-20, -12);
  }
  starGeo.setAttribute('position', new THREE.BufferAttribute(starPos, 3));
  const starMat = new THREE.PointsMaterial({
    color: '#ffffff',
    size: 0.12,
    transparent: true,
    opacity: 0,
    depthWrite: false,
    fog: false,
  });
  const stars = new THREE.Points(starGeo, starMat);
  scene.add(stars);

  // --- shared building materials (recoloured by the day cycle)
  const buildingMat = new THREE.MeshStandardMaterial({ color: '#150f2c', roughness: 0.9, metalness: 0 });
  const roofMat = new THREE.MeshBasicMaterial({ color: '#5fd6ff' });

  // --- parallax far skyline (slow-scrolling silhouettes for depth)
  const farGroup = new THREE.Group();
  scene.add(farGroup);
  const farMat = new THREE.MeshBasicMaterial({ color: '#0c0a1f' });
  const farBuildings: any[] = [];
  for (let i = 0; i < (isLowEndDevice ? 14 : 22); i++) {
    const w = rand(1.5, 3.2);
    const h = rand(3, 8);
    const m = new THREE.Mesh(new THREE.BoxGeometry(w, h, 1), farMat);
    m.position.set(-26 + i * 2.6, h / 2 - 0.5, -11);
    farGroup.add(m);
    farBuildings.push(m);
  }

  // --- buildings (recycled pool)
  const boxGeo = new THREE.BoxGeometry(1, 1, DEPTH);
  const roofGeo = new THREE.BoxGeometry(1, 0.14, DEPTH);
  const platforms: any[] = [];
  const freePool: any[] = [];

  function makePlatform() {
    const group = new THREE.Group();
    const building = new THREE.Mesh(boxGeo, buildingMat);
    const roof = new THREE.Mesh(roofGeo, roofMat);
    roof.position.z = DEPTH / 2 - 0.05;
    group.add(building);
    group.add(roof);
    scene.add(group);
    return { group, building, roof, centerX: 0, width: 1, top: BASE_TOP, left: 0, right: 0 };
  }

  function configurePlatform(p: any, centerX: number, width: number, top: number) {
    const H = top + 5;
    p.centerX = centerX;
    p.width = width;
    p.top = top;
    p.left = centerX - width / 2;
    p.right = centerX + width / 2;
    p.group.position.x = centerX;
    p.building.scale.set(width, H, 1);
    p.building.position.y = top - H / 2;
    p.roof.scale.set(width, 1, 1);
    p.roof.position.y = top;
  }

  let lastTop = BASE_TOP;
  function spawnNext() {
    const last = platforms[platforms.length - 1];
    const speedFrac = clamp01((speed - START_SPEED) / (MAX_SPEED - START_SPEED));
    const gap = rand(2.0, 2.6 + speedFrac * 1.4);
    const width = rand(2.4, 4.2);
    // keep consecutive rooftops within reach of a jump
    let top = lastTop + rand(-1.0, 1.0);
    top = Math.max(2.6, Math.min(4.4, top));
    lastTop = top;
    const centerX = last.right + gap + width / 2;
    const p = freePool.length ? freePool.pop() : makePlatform();
    if (!p.group.parent) scene.add(p.group);
    configurePlatform(p, centerX, width, top);
    platforms.push(p);
  }

  // recycle buildings that have scrolled off the left edge into the free pool
  function cullPlatforms() {
    while (platforms.length > 1 && platforms[0].right < CULL_X) {
      const p = platforms.shift();
      scene.remove(p.group);
      freePool.push(p);
    }
  }
  function fillAhead() {
    while (platforms[platforms.length - 1].right < SPAWN_AHEAD) spawnNext();
  }

  // ----------------------------------------------------------------- character
  const char = new THREE.Group();
  const charMat = new THREE.MeshStandardMaterial({
    color: '#f6f8ff',
    emissive: '#7df9ff',
    emissiveIntensity: 0.55,
    roughness: 0.4,
  });
  const body = new THREE.Mesh(new THREE.CapsuleGeometry(0.22, 0.5, 4, 8), charMat);
  body.position.y = 0.82;
  const head = new THREE.Mesh(new THREE.SphereGeometry(0.21, 12, 12), charMat);
  head.position.y = 1.34;
  const legGeo = new THREE.BoxGeometry(0.13, 0.42, 0.13);
  const legL = new THREE.Mesh(legGeo, charMat);
  const legR = new THREE.Mesh(legGeo, charMat);
  legL.position.set(-0.1, 0.21, 0.04);
  legR.position.set(0.1, 0.21, -0.04);
  char.add(body, head, legL, legR);
  char.position.x = CHAR_X;
  scene.add(char);

  // a soft glow under the runner so it always reads against the sky
  const charGlow = new THREE.Sprite(
    new THREE.SpriteMaterial({ map: makeGlowTexture(), color: '#7df9ff', transparent: true, opacity: 0.5, depthWrite: false, fog: false })
  );
  charGlow.scale.set(2.6, 2.6, 1);
  charGlow.position.y = 0.8;
  char.add(charGlow);

  // ----------------------------------------------------------------- state
  let state = 'ready'; // 'ready' | 'playing' | 'over'
  let feetY = BASE_TOP;
  let vy = 0;
  let onGround = true;
  let speed = START_SPEED;
  let distance = 0;
  let runPhase = 0;
  let lastReported = -1;
  let overSince = 0;
  let highScore = 0;
  try {
    highScore = parseInt(localStorage.getItem('skylineHigh') || '0', 10) || 0;
  } catch (e) {}
  reportHigh(highScore);

  function resetWorld() {
    // return all buildings to the free pool
    while (platforms.length) {
      const p = platforms.pop();
      scene.remove(p.group);
      freePool.push(p);
    }
    lastTop = BASE_TOP;
    const start = freePool.length ? freePool.pop() : makePlatform();
    if (!start.group.parent) scene.add(start.group);
    // wide, flat starting rooftop centred over the runner for safe runway
    configurePlatform(start, CHAR_X + 2, 11, BASE_TOP);
    platforms.push(start);
    fillAhead();
    feetY = BASE_TOP;
    vy = 0;
    onGround = true;
    speed = START_SPEED;
    distance = 0;
    lastReported = -1;
    char.rotation.z = 0;
    char.position.y = BASE_TOP;
    reportScore(0);
  }

  function startPlaying() {
    resetWorld();
    state = 'playing';
    reportState('playing');
  }

  function gameOver() {
    state = 'over';
    overSince = performance.now();
    const score = Math.floor(distance);
    if (score > highScore) {
      highScore = score;
      try {
        localStorage.setItem('skylineHigh', String(highScore));
      } catch (e) {}
      reportHigh(highScore);
    }
    reportState('over');
  }

  function jump() {
    if (onGround) {
      vy = JUMP_V;
      onGround = false;
    }
  }

  function handleInput() {
    if (state === 'ready') startPlaying();
    else if (state === 'playing') jump();
    else if (state === 'over' && performance.now() - overSince > 500) startPlaying();
  }

  // ----------------------------------------------------------------- input
  function onKey(e: KeyboardEvent) {
    if (e.code === 'Space' || e.code === 'ArrowUp' || e.key === ' ') {
      e.preventDefault();
      handleInput();
    }
  }
  function onPointer(e: Event) {
    e.preventDefault();
    handleInput();
  }
  window.addEventListener('keydown', onKey);
  renderer.domElement.addEventListener('pointerdown', onPointer);

  function onResize() {
    camera.aspect = window.innerWidth / window.innerHeight;
    camera.updateProjectionMatrix();
    renderer.setSize(window.innerWidth, window.innerHeight);
  }
  window.addEventListener('resize', onResize);

  // ----------------------------------------------------------------- loop
  resetWorld();
  state = 'ready';
  reportState('ready');

  const skyColor = new THREE.Color();
  const buildColor = new THREE.Color();
  const accentColor = new THREE.Color();
  const clock = new THREE.Clock();
  let rafId = 0;
  let disposed = false;

  function platformUnder(x: number) {
    for (let i = 0; i < platforms.length; i++) {
      const p = platforms[i];
      if (x >= p.left && x <= p.right) return p;
    }
    return null;
  }

  function animate() {
    if (disposed) return;
    rafId = requestAnimationFrame(animate);
    const dt = Math.min(clock.getDelta(), 0.05);
    const elapsed = clock.elapsedTime;

    // --- day / night cycle
    const sunAngle = (elapsed / CYCLE_SECONDS) * Math.PI * 2 + 0.35;
    const e = Math.sin(sunAngle);
    sun.position.x = Math.cos(sunAngle) * 11;
    sun.position.y = 3 + e * 7;
    sunLight.position.set(sun.position.x, sun.position.y + 4, 6);
    rampColor(skyColor, 'sky', e);
    rampColor(buildColor, 'building', e);
    rampColor(accentColor, 'accent', e);
    scene.background = skyColor;
    fog.color.copy(skyColor);
    buildingMat.color.copy(buildColor);
    roofMat.color.copy(accentColor);
    charMat.emissive.copy(accentColor);
    (charGlow.material as any).color.copy(accentColor);
    ambient.intensity = rampNum('amb', e);
    sunLight.intensity = rampNum('sun', e);
    // sun warm near horizon, pale high; becomes a moon when below
    if (e < -0.08) {
      sunMat.color.set('#cfd8ff');
      glowMat.color.set('#9fb0ff');
    } else {
      sunMat.color.copy(accentColor).lerp(tmpA.set('#fff3c8'), 0.5);
      glowMat.color.copy(sunMat.color);
    }
    starMat.opacity = clamp01(-e * 1.6 - 0.1);

    // --- gameplay
    if (state === 'playing') {
      speed = Math.min(MAX_SPEED, speed + SPEED_RAMP * dt);
      const dx = speed * dt;
      distance += dx;

      // scroll buildings + recycle
      for (let i = 0; i < platforms.length; i++) {
        const p = platforms[i];
        p.centerX -= dx;
        p.left -= dx;
        p.right -= dx;
        p.group.position.x = p.centerX;
      }
      cullPlatforms();
      fillAhead();

      // physics
      const p = platformUnder(CHAR_X);
      if (onGround) {
        if (p) {
          feetY = p.top;
        } else {
          onGround = false; // ran off an edge
          vy = 0;
        }
      }
      if (!onGround) {
        feetY += vy * dt;
        vy -= GRAVITY * dt;
        const lp = platformUnder(CHAR_X);
        if (vy <= 0 && lp && feetY <= lp.top) {
          feetY = lp.top;
          vy = 0;
          onGround = true;
        }
        if (feetY < DEATH_Y) gameOver();
      }

      // run animation
      runPhase += dx * 1.6;
      const swing = onGround ? Math.sin(runPhase) * 0.7 : 0.5;
      legL.rotation.x = swing;
      legR.rotation.x = -swing;
      char.rotation.z = onGround ? 0 : Math.min(0.5, Math.max(-0.3, -vy * 0.03));
      const bob = onGround ? Math.abs(Math.sin(runPhase)) * 0.05 : 0;
      char.position.y = feetY + bob;

      const score = Math.floor(distance);
      if (score !== lastReported) {
        lastReported = score;
        reportScore(score);
      }
    } else if (state === 'over') {
      // let the runner tumble off-screen
      feetY += vy * dt;
      vy -= GRAVITY * dt;
      char.position.y = feetY;
      char.rotation.z += dt * 4;
    } else {
      // ready: gentle idle bob
      runPhase += dt * 4;
      char.position.y = feetY + Math.abs(Math.sin(runPhase)) * 0.04;
    }

    // --- parallax skyline drifts slowly
    if (state === 'playing') {
      const fdx = speed * dt * 0.25;
      for (let i = 0; i < farBuildings.length; i++) {
        const m = farBuildings[i];
        m.position.x -= fdx;
        if (m.position.x < -30) m.position.x += farBuildings.length * 2.6;
      }
    }
    farMat.color.copy(buildColor).multiplyScalar(0.7);

    renderer.render(scene, camera);
  }
  animate();

  // ----------------------------------------------------------------- cleanup
  return function dispose() {
    disposed = true;
    cancelAnimationFrame(rafId);
    window.removeEventListener('keydown', onKey);
    window.removeEventListener('resize', onResize);
    renderer.domElement.removeEventListener('pointerdown', onPointer);
    renderer.dispose();
    if (renderer.domElement.parentNode) {
      renderer.domElement.parentNode.removeChild(renderer.domElement);
    }
  };
}

// radial-gradient glow sprite texture
function makeGlowTexture() {
  const size = 128;
  const canvas = document.createElement('canvas');
  canvas.width = canvas.height = size;
  const ctx = canvas.getContext('2d')!;
  const g = ctx.createRadialGradient(size / 2, size / 2, 0, size / 2, size / 2, size / 2);
  g.addColorStop(0, 'rgba(255,255,255,1)');
  g.addColorStop(0.25, 'rgba(255,255,255,0.5)');
  g.addColorStop(1, 'rgba(255,255,255,0)');
  ctx.fillStyle = g;
  ctx.fillRect(0, 0, size, size);
  const tex = new THREE.CanvasTexture(canvas);
  return tex;
}
