import React, { useEffect, useRef, useState } from "react";
import CssBaseline from "@mui/material/CssBaseline";
import { createTheme, ThemeProvider } from "@mui/material/styles";
import StartThreeJS from "./city3d";
import { Box, Link } from "@mui/material";
import LinkedInIcon from "@mui/icons-material/LinkedIn";

const theme = createTheme({
  typography: {
    fontFamily: ["Montserrat", "Nunito", "Roboto", "Helvetica Neue", "Arial", "sans-serif"].join(
      ","
    ),
  },
});

const LINKEDIN_URL = "https://www.linkedin.com/in/daniel-odea/";
const MUSESCORE_URL = "https://musescore.com/tlx494";

// strong shadow so white text stays readable over any sky colour
const SHADOW = "0 2px 14px rgba(0,0,0,0.65), 0 0 3px rgba(0,0,0,0.8)";

const Pipe = () => <span style={{ color: "rgba(255,255,255,0.45)" }}> | </span>;

const MuseLink = ({ children }: { children: React.ReactNode }) => (
  <Link
    href={MUSESCORE_URL}
    target="_blank"
    rel="noopener noreferrer"
    underline="hover"
    sx={{ color: "inherit", cursor: "pointer", pointerEvents: "auto" }}
  >
    {children}
  </Link>
);

function App() {
  const cityRef = useRef<any>(null);
  const [score, setScore] = useState(0);
  const [high, setHigh] = useState(0);
  const [gameState, setGameState] = useState<"ready" | "playing" | "over">("ready");

  useEffect(() => {
    const dispose = StartThreeJS(cityRef, {
      onScore: setScore,
      onHigh: setHigh,
      onState: setGameState,
    });
    return dispose;
  }, []);

  return (
    <ThemeProvider theme={theme}>
      <CssBaseline />
      {/* canvas mount — fills the viewport, behind everything */}
      <div
        ref={cityRef}
        id="city"
        style={{ position: "fixed", inset: 0, width: "100vw", height: "100vh" }}
      />

      {/* HUD overlay — pointer-events pass through to the canvas so taps jump */}
      <div
        style={{
          position: "fixed",
          inset: 0,
          pointerEvents: "none",
          color: "#fff",
          textShadow: SHADOW,
          userSelect: "none",
          WebkitUserSelect: "none",
        }}
      >
        {/* identity, top-left */}
        <div style={{ position: "absolute", top: 22, left: 28 }}>
          <h1 style={{ margin: 0, fontFamily: "Dune", fontSize: "2em", letterSpacing: 1 }}>
            DANIEL O'DEA
          </h1>
          <Box sx={{ mt: 0.5, fontSize: "0.95rem", color: "rgba(255,255,255,0.92)" }}>
            software engineer <Pipe /> <MuseLink>pianist</MuseLink> <Pipe />{" "}
            <MuseLink>composer</MuseLink> <Pipe /> artist <Pipe /> writer
          </Box>
        </div>

        {/* LinkedIn, top-right */}
        <Link
          href={LINKEDIN_URL}
          target="_blank"
          rel="noopener noreferrer"
          aria-label="LinkedIn"
          sx={{
            position: "absolute",
            top: 22,
            right: 26,
            color: "#fff",
            pointerEvents: "auto",
            display: "inline-flex",
            opacity: 0.9,
            transition: "opacity 0.2s, transform 0.2s",
            "&:hover": { opacity: 1, transform: "scale(1.12)" },
          }}
        >
          <LinkedInIcon sx={{ fontSize: 30 }} />
        </Link>

        {/* score, top-center */}
        <div
          style={{
            position: "absolute",
            top: 24,
            left: 0,
            right: 0,
            textAlign: "center",
          }}
        >
          <div style={{ fontSize: "2.4rem", fontWeight: 700, lineHeight: 1 }}>
            {String(score).padStart(4, "0")}
          </div>
          <div style={{ fontSize: "0.8rem", letterSpacing: 2, opacity: 0.85 }}>
            BEST {String(high).padStart(4, "0")}
          </div>
        </div>

        {/* center messages */}
        {gameState !== "playing" && (
          <div
            style={{
              position: "absolute",
              top: "40%",
              left: 0,
              right: 0,
              textAlign: "center",
            }}
          >
            {gameState === "ready" ? (
              <>
                <div style={{ fontSize: "2.6rem", fontWeight: 800, letterSpacing: 3 }}>
                  SKYLINE RUNNER
                </div>
                <div style={{ marginTop: 12, fontSize: "1.05rem", opacity: 0.95 }}>
                  press <b>space</b> / tap to jump the gaps
                </div>
              </>
            ) : (
              <>
                <div style={{ fontSize: "2.6rem", fontWeight: 800, letterSpacing: 3 }}>
                  GAME OVER
                </div>
                <div style={{ marginTop: 10, fontSize: "1.3rem" }}>
                  score <b>{score}</b>
                  {score >= high && score > 0 ? "  ·  new best!" : `  ·  best ${high}`}
                </div>
                <div style={{ marginTop: 10, fontSize: "1rem", opacity: 0.92 }}>
                  press <b>space</b> / tap to run again
                </div>
              </>
            )}
          </div>
        )}
      </div>
    </ThemeProvider>
  );
}

export default App;
